const rotate = (items, offset) => items.map((_, i) => items[(i + offset) % items.length])

function buildProblems(checks, lessonIndex) {
  return checks.map((check, questionIndex) => {
    const offset = (lessonIndex + questionIndex) % 4
    return {
      type: 'mc',
      question: { en: check[0], zh: check[1] },
      choices: rotate(check[2], offset),
      answer: (4 - offset) % 4,
      explanation: { en: check[3], zh: check[4] },
    }
  })
}

function buildLesson(config, lessonIndex) {
  return {
    id: config.id,
    title: config.title,
    titleZh: config.titleZh,
    content: [
      { type: 'h2', en: config.heading, zh: config.headingZh },
      { type: 'p', en: config.intro, zh: config.introZh },
      { type: 'h3', en: 'The economic model', zh: '经济模型' },
      { type: 'p', en: config.model, zh: config.modelZh },
      ...(config.math || []).map(tex => ({ type: 'math', tex })),
      { type: 'h3', en: 'How to reason on the AP exam', zh: 'AP 考试中的推理方法' },
      { type: 'p', en: config.skill, zh: config.skillZh },
      { type: 'p', en: 'For every model, practice all four AP skill categories: define the principle precisely, interpret a stated outcome, manipulate the model after one condition changes, and communicate the result with a correctly labeled graph or calculation. A strong explanation gives a causal chain rather than a memorized direction: identify the initial change, name the curve or marginal quantity affected, describe the adjustment, and state the final effect on price, quantity, profit, efficiency, or welfare.', zh: '学习每个模型时都要练习 AP 的四类技能：准确界定原理、解释给定结果、在一个条件变化后推演模型，并用标注正确的图形或计算表达结论。高质量解释不是背诵方向，而是给出因果链：确定初始变化，指出受影响的曲线或边际量，描述调整过程，再说明价格、数量、利润、效率或福利的最终变化。' },
      { type: 'note', en: config.note, zh: config.noteZh },
      ...config.examples.map((example, i) => ({
        type: 'example',
        title: { en: `Worked Example ${i + 1}`, zh: `例题 ${i + 1}` },
        problem: { en: example[0], zh: example[1] },
        solution: [
          { type: 'p', en: example[2], zh: example[3] },
          ...(example[4] ? [{ type: 'math', tex: example[4] }] : []),
        ],
      })),
    ],
    problems: buildProblems(config.checks, lessonIndex),
  }
}

let lessonNumber = 0
const L = config => buildLesson(config, lessonNumber++)

